def range_summary(nums):
    if not nums:  # handle edge case of empty list
        return ''

    distinct_nums = sorted(set(nums))
    ranges = []

    for i in range(len(distinct_nums) - 1):
        start, end = distinct_nums[i], distinct_nums[i + 1]
        if end == start + 1:
            if ranges and ranges[-1].split('-')[0] == str(start):
                ranges[-1] = f"{start}-{end}"
            else:
                ranges.append(f"{start}-{end}")
        else:
            if ranges and ranges[-1].split('-')[0] != str(start):
                ranges.append(str(start))
            elif end - start > 1:  # handle edge case of single number
                ranges.append(f"{start}-{end}")

    return ','.join(ranges)
